var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어서 오세요! 카페 스트레가입니다!","JPN":"いらっしゃいませ！　カフェ・ストレガへようこそ！","ENG":"Welcome to Cafe Strega!","TWN":"歡迎光臨史特雷加咖啡廳！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BELL"},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"에어컨 바람이 시원하군요. 몸을 식힐 수 있겠습니다.","JPN":"エアコンの風が涼しいですね。体を冷やすことができそうです。","ENG":"The air conditioning breeze feels nice. I should be able to cool down here.","TWN":"這裡的冷氣好涼快，可以讓身體降溫一下。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안은 시원해서 다행이야. 치후유. 옷 가게인 줄 알았는데, 카페일 줄은 몰랐네.","JPN":"中が涼しくて良かったわね、千冬。服屋かと思ったけど、カフェだったのね。","ENG":"It is good that the temperature is cool inside. I thought this would be a clothing store, but it's a cafe!","TWN":"幸好室內很涼爽。我還以為這裡是服裝店，沒想到是咖啡廳。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"<color=#ffd34c> 카페 스트레가, 이번 할로윈에도 우승인가?</color>라는 제목이었으니까요.","JPN":"<color=#ffd34c>カフェ・ストレガ、今度のハロウィンも優勝か？</color>というタイトルでしたからね。","ENG":"Well, the title did say, <color=#ffd34c>\\"Cafe Strega, Another Victory for This Year's Halloween?\\"</color>","TWN":"因為標題寫著，<color=#ffd34c> 今年萬聖節史特雷加咖啡廳也會獲勝嗎？</color>"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"아무래도 의상을 포함해 이것저것 다루는 게 아닌가 싶습니다만.","JPN":"衣装を含め、あれこれ扱っているのではと。","ENG":"I am guessing they treat various products, including costumes.","TWN":"看來這邊應有盡有，要找衣服也沒問題。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"흐음~ 정말 마녀 컨셉의 카페라, 분위기가 신선해서 더 좋지 않아?","JPN":"ふ～ん、本物の魔女コンセプトのカフェか。斬新な雰囲気もいい感じだね？","ENG":"Hmmm! A witch-themed cafe, it feels refreshing.","TWN":"嗯～真的很喜歡這個魔女主題的咖啡廳，不覺得很特別嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"예. 그렇습니다. 당주님. 마치 진짜 마녀들이 차린 카페 같군요.","JPN":"はい。同感です、当主。まるで本物の魔女が経営しているカフェのようです。","ENG":"Yes. I agree, my lady. It truly does look like a cafe set up by real witches.","TWN":"是的，堂主。感覺就像是真正的魔女開的咖啡廳一樣。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"게다가, 이곳은 시원해서 좋습니다.","JPN":"それに、涼しいのが良いです。","ENG":"Besides, I like how cool it is in here.","TWN":"而且，這裡好涼，我很喜歡。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후훗. 그러니?","JPN":"ふふっ、そう？","ENG":"Hehe. Is that so?","TWN":"呵呵，是嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"소, 손님……! 죄송하지만, 그 뿔…… 진짠가요?","JPN":"お、お客さん……！　すみません、その角……本物ですか？","ENG":"E-excuse me...! Is that horn... real?","TWN":"這位…客人…！不好意思，請問那個角…是真的吗？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"우와! 대단하잖아?! 손님 혹시 코스 플레이어야? 아니면 진짜 요괴?","JPN":"うわ！　すごい！！　お客さん、もしかしてコスプレイヤー？　それとも本当の妖怪？","ENG":"Wow! That's amazing! Are you a cosplayer? Or a real mythical creature?","TWN":"哇！好厲害！客人你是在角色扮演嗎？還是你是真的妖怪？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"저는 그저 당주님을 지키는 호위 무사일 뿐입니다.","JPN":"私は当主をお守りしている、ただの護衛です。","ENG":"I am merely a bodyguard tasked with protecting Lady Nanahara.","TWN":"我只是堂主身邊的護衛武士而已。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후훗. 귀여운 점원분들이시네요.","JPN":"ふふっ、かわいらしい店員さんたちですね。","ENG":"Hehe. The servers are adorable here.","TWN":"呵呵，好可愛的店員。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"두 분은 어디서 오셨나요?","JPN":"お二人はどちら様ですか？","ENG":"Where did you two come from?","TWN":"你們是從哪裡來的呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희는 나나하라 가문의 치나츠, 치후유라고 합니다.","JPN":"私たちは七原家の千夏と千冬と申します。","ENG":"We are Chinatsu and Chifuyu of the Nanahara family.","TWN":"我們是七原家族的千夏和千冬。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"꼬마 숙녀분들. 손님을 곤란하게 하면 안 되지~","JPN":"お嬢ちゃんたち。お客さんを困らせちゃダメよ～","ENG":"Hey little ladies. Stop bothering the customers!","TWN":"你們二個，不可以打擾客人喔～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"너넨 얼른 다른 손님들 주문이나 받아. 예의 없게 무슨 짓이야?","JPN":"汝らは他のお客さんの注文でも受けてこい。こちらのお客さんに失礼ではないか。","ENG":"Go take the other customers' orders. You're being rude.","TWN":"還不快去幫其他客人點餐，搞什麼！有沒有禮貌！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"괜찮아요. 점원분들이 참 귀여운걸요.","JPN":"気にしないでください。店員さんがとても可愛いですね。","ENG":"It is all right. Your servers are very sweet.","TWN":"沒關係，她們很可愛。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이쪽은 깜짝 놀랐다고.","JPN":"こっちはびっくりしたぞ。","ENG":"You surprised us, you know.","TWN":"我剛嚇一跳，"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"웬 불덩이가 들어와서 환자인 줄 알았더니 멀쩡하지 뭐야?","JPN":"火の玉が入ってきて患者かと思ったら、普通にしているではないか。","ENG":"A ball of fire just walked into the cafe, and we thought it was a sick person. But she looks fine.","TWN":"想說哪來的火球，以為是病人，結果看起來很健康呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제 동생의 체온이 좀 높거든요.","JPN":"妹の体温は少々高いのです。","ENG":"My sister runs quite hot.","TWN":"我妹妹的體溫有點高。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"매일 에어컨을 가까이하고 있으니 걱정이랍니다.","JPN":"毎日エアコンのそばにばかりいて心配になります。","ENG":"It concerns me that she always sits near the air conditioner.","TWN":"她每天都待在冷氣旁，真讓人擔心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"다, 당주님!","JPN":"と、当主！","ENG":"M-my lady!","TWN":"堂，堂主！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"언니라고? 흐음……","JPN":"妹？　ふーん……","ENG":"Sister? Hmm...","TWN":"你是姊姊嗎？嗯…"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"나는 이쪽이 동생인 줄 알았지 뭐야?","JPN":"妾はてっきり汝が妹かと思ったが。","ENG":"I thought you were the younger one.","TWN":"我還以為你是妹妹呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"동생……","JPN":"妹……","ENG":"Younger... one...","TWN":"妹妹…"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"꼬맹이가 늙은이처럼 말하니까 언니인 것 같긴 하네.","JPN":"子どもが年寄りのように話すところを見ると、姉で間違いはないようだな。","ENG":"You do sound like the older sister, since you're talking like an old woman with the appearance of a child.","TWN":"個子矮矮的，語氣卻像個老頭子一樣，確實是姊姊沒錯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그래서, 여기까진 무슨 일로 온 거야?","JPN":"で、ここには何の用で来たんだ？","ENG":"So, what brings you here?","TWN":"所以你們來這裡是要想什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"애처럼…… 생겨서는…… 늙은이처럼……","JPN":"子ども……年寄り……","ENG":"An old woman... with the appearance... of a child...","TWN":"長得像小孩…與氣像老頭子……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"크흠……","JPN":"コホン……","ENG":"Ahem...","TWN":"咳咳……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"유원지에서 축제가 열리는데 드레스코드가 필요하다고 해 이곳까지 오게 되었습니다.","JPN":"遊園地でお祭りが開かれるのですが、ドレスコードが必要だと知り、こちらに伺った次第です。","ENG":"Well, there is a festival in the amusement park, and we heard that there is a dress code to follow. So we ended up here.","TWN":"因為遊樂園有特別活動，需要穿著規定的服裝，所以我們才會來這裡找衣服。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머~ 유원지 축제? 벌써 그렇게 됐네.","JPN":"あら～遊園地のお祭り？　もうそんな時期なのね。","ENG":"Oh my! The amusement park festival? I guess it's that time already.","TWN":"喔～遊樂園的活動嗎？又到那個時候啦？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"게다가 옷을 찾으러 여기까지 왔다니, 우리가 코스튬으로 유명하긴 하지~","JPN":"しかも服を探してここまで来たなんて。確かに、私たちがコスチューム作りで有名ではあるわよね～","ENG":"And you're here for an outfit? We are pretty well known for our costumes, I guess!","TWN":"你們還特地跑到這裡來找衣服，看來我們的衣服有打出名號喔～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"흠흠…… 보는 눈이 좀 있네.","JPN":"ふむふむ……まあ、見る目はあるな。","ENG":"Ahem... Seems like you have good taste.","TWN":"哼哼…算你們有眼光。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"자, 여기 내가 특별한 재료를 넣어서 만든 음료야. 몸속의 열을 조금 내려줘.","JPN":"ほら、妾が特別な材料を入れて作った飲み物だ。体内の熱を少し下げてくれる。","ENG":"Here. I made this drink with some special ingredients. It'll lower your body temperature.","TWN":"來，這是我用特別的材料做的飲料，可以讓你的身體降溫。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"크흠! 기분이 좋아서 그런 건 아니고.","JPN":"コホン！　気分がいいからあげるわけではないぞ。","ENG":"Kahem! It's not that I'm flattered or anything.","TWN":"咳咳！我可不是因為開心才請你們喝飲料喔。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그냥 당신 동생이 계속 열을 뿜고 있으면 에어컨 비가 많이 나오니까!","JPN":"ただ、汝の妹がずっと熱を出しているとエアコン代が高くつくからだ！","ENG":"Just because we'll have to pay more for electricity if your sister keeps emitting heat!","TWN":"只是因為你妹妹體溫太高，我怕冷氣費用會很高！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"감사합니다. 그럼……","JPN":"ありがとうございます。それでは……","ENG":"I appreciate it. Now then...","TWN":"謝謝，那我就不客氣…"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"시원합니다! 게다가 맛있기까지……!","JPN":"冷たいです！　しかもおいしい……！","ENG":"It is refreshing! And delicious...!","TWN":"好冰！而且很好喝……！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"거기 언니도 한 잔 마셔볼래?","JPN":"汝も一杯飲んでみるか？","ENG":"Do you want to try a sip too?","TWN":"姊姊也來一杯吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 감사합니다.","JPN":"はい、ありがとうございます。","ENG":"Yes, thank you.","TWN":"好的，謝謝。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…… 레모네이드?","JPN":"……レモネード？","ENG":"...Lemonade?","TWN":"……檸檬水？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"에퉤퉤.","JPN":"ううう。","ENG":"Pft. Pft pft.","TWN":"呸呸呸。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"응? 뭐야, 기껏 만들어줬더니 왜 이리 죽상이야?","JPN":"うん？　なんだ、せっかく作ってやったのに、どうしてそのような顔をしているのだ？","ENG":"Hmm? What's with the frown?","TWN":"蛤？搞什麼，人家辛苦做的，怎麼這麼過分？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제, 제가…… 레몬을 별로 안 좋아해서요.","JPN":"わ、私……レモンはあまり好きではないのです。","ENG":"I-I... I am not a big fan of lemons.","TWN":"我，我…不太喜歡檸檬。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"흐흥. 그래?","JPN":"フフン。そうか。","ENG":"Hn-hm. Is that right?","TWN":"嗯哼，是喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"언니 맞아? 하긴, 이렇게 가리는 게 많으니 동생 몸이 좀 더……","JPN":"本当に姉か？　まあ、こうして好き嫌いが多いから、妹の体の方がもっと……","ENG":"Are you sure you're the older one? Well, I guess your sister is more physically developed because you're so picky...","TWN":"你真的是姊姊嗎？也對，姊姊這麼難搞，妹妹氣到發熱……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라. 손님을 놀리면 못써.","JPN":"ラウラ。お客さんをからかっちゃダメよ。","ENG":"Laura. Stop teasing the customers.","TWN":"蘿拉，不可以這樣亂開客人玩笑。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"으음……","JPN":"うう……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"다, 당주님……","JPN":"と、当主……","ENG":"M-my lady...","TWN":"堂，堂主……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"칫. 반응이 재밌어서 그랬다. 왜. 꼬맹이는 좀 기다려. 다른 걸 갖다줄게.","JPN":"チッ。反応が面白くてつい。ちびっ子はもう少し待っていろ。他の飲み物を持ってくる。","ENG":"Tch. I just thought her reaction was funny. Is that a problem? Anyway, wait a bit, kid. I'll get you something else.","TWN":"嘖，因為她的反應很好玩嘛，怎樣？你等等，我拿其他的給你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그나저나, 아무리 개성이 넘치는 시대라지만 두 사람 다 옷차림이 특이하단 말이지.","JPN":"それにしても、個性あふれる時代だとは言え、二人とも服装が変わっているな。","ENG":"Hmm. I know clothes aren't a big deal in this day and age, but both of you are wearing something quite peculiar.","TWN":"不過，雖然現在大家的穿著都很有個人風格，但你們二個的穿著還真特別。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"무녀와 호위 무사라니. 시선은 엄청 끌겠어. 게다가…… 노출도 장난 아니고.","JPN":"巫女と護衛とは。ものすごく人の目を引きそうだ……露出の面でも。","ENG":"A priestess and her bodyguard. I bet that attracts a lot of attention. Plus... it's really revealing.","TWN":"巫女和護衛武士，應該很引人注目吧。而且…衣服還很暴露。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"제 몸에 열이 많아 평범한 옷으로는 이를 다스리기가 어렵습니다.","JPN":"私の体に熱が多いので、普通の服装では調節することができないのです。","ENG":"It is difficult to suppress the heat within my body with ordinary clothes.","TWN":"因為我體內的溫度很高，普通的衣服散熱。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그래서 그라운드 원의 백화점에서도 저에게 맞는 옷을 찾는 게 힘들더군요.","JPN":"グラウンド・ワンのデパートにも行ったのですが、私に合う服が見つからず。","ENG":"Which made it hard to find something suitable, even at the department store in Ground One.","TWN":"所以在G1的百貨公司也找不到適合我的衣服。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"음…… 동생 같은 경우는 열도 열이지만…… 좀 더 다른 부분이…….","JPN":"うむ……妹の場合は熱も熱だが……もっとこう、別の問題が……","ENG":"Hmm... Your little sister's heat is an issue, but... there's also...","TWN":"嗯…像你妹妹這種情況，體溫高是高……還有其他部分……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이건 그냥 개인적인 욕심인데 말이지.","JPN":"これはただの個人的な欲なのだが。","ENG":"Well, this is just personal curiosity, but...","TWN":"這是我的個人想法。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이렇게 독특한 소재를 두고 갑자기 창작혼이 불타올라서 말이야.","JPN":"このように個性的な素材を見ると、がぜん創造意欲が湧いてきてな。","ENG":"Your unique features just piqued my creative interests.","TWN":"看到這麼獨特的素材，使我突然有好多創作的靈感。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"때마침 옷을 찾으러 왔다며? 원래는 비싼 값을 받는 거지만…….","JPN":"ちょうど服を探しに来たのだろう？　本来なら高く売るところだが……","ENG":"You came here looking for costumes, right? I'd normally ask for a huge commission fee, but...","TWN":"你說你們是來找衣服的？本來要算你們很貴的……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"내가 둘에게 옷을 만들어줄게.","JPN":"妾が二人に服をプレゼントしてやろう。","ENG":"I'll just make your costumes.","TWN":"我就替你們做衣服吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};